use rulebench_protocol::RulebenchCapabilityManifestDto;

pub fn render_capability_manifest_artifact(
    manifest: &RulebenchCapabilityManifestDto,
) -> Result<String, serde_json::Error> {
    let encoded = serde_json::to_string_pretty(manifest)?;
    Ok(format!(
        "// GENERATED by rulebench-process-host/emit_capability_manifest; schema {}. Do not hand-edit.\n\n\
         import type {{ RulebenchCapabilityManifestDto }} from '@asha-rulebench/protocol';\n\n\
         export const rustCapabilityManifest: RulebenchCapabilityManifestDto = {encoded};\n",
        manifest.generated_artifact_schema,
    ))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn committed_artifact_records_the_concrete_host_emitter() {
        let committed = include_str!("../../../../artifacts/generated/rust-capability-manifest.ts");
        assert!(committed.starts_with(
            "// GENERATED by rulebench-process-host/emit_capability_manifest; schema "
        ));
        assert!(committed.contains("manifestId"));
        let _renderer: fn(&RulebenchCapabilityManifestDto) -> Result<String, serde_json::Error> =
            render_capability_manifest_artifact;
    }
}
